def agentic_rag_loop(agent, query: str, max_iterations=5):
    ctx = {'query': query, 'sources': [], 'plan': None}

    for i in range(max_iterations):
        if ctx.get('final_answer'):
            break

        # Plan subqueries
        plan = agent.plan(ctx)
        ctx['plan'] = plan

        # Retrieve
        sources = agent.retrieve(plan)
        ctx['sources'].extend(sources)

        # Check convergence
        if agent.converged(ctx):
            ctx['final_answer'] = agent.synthesize(ctx)
            break

    return ctx['final_answer']

def generate_cited_response(agent, ctx):
    response = agent.llm.generate(
        ctx['sources'],
        instruction="Synthesize answer with citations: {query}".format(
            query=ctx['query']
        )
    )

    citations = extract_citations(response)
    faithfulness = verify_citations(response, ctx['sources'])

    return {
        'answer': response,
        'citations': citations,
        'faithfulness_score': faithfulness,
        'sources_used': len(ctx['sources'])
    }

