def check_citation_accuracy(ctx):
    response = ctx['response']
    sources = ctx['sources']
    citations = extract_citations(response)

    valid_citations = 0
    for citation in citations:
        source_text = find_source(citation.source_id, sources)
        if semantic_similarity(response, source_text) > 0.8:
            valid_citations += 1

    score = valid_citations / len(citations) if citations else 1.0
    return {'pass': score > 0.7, 'score': score}

